/**
 * Build a compact context summary for the Master Planner.
 *
 * The planner does not need the raw 180 sales rows -- that would blow the
 * context budget. We extract the headline numbers and the SKUs already
 * past or near reorder so the planner can pick the right subgoal first.
 *
 * Inputs reach this node via cross-node references to the four CSV-parse
 * nodes upstream. We do NOT mutate them, only summarize.
 */
const inventory = $('Read Inventory JSON').all().map(i => i.json);
const sales     = $('Read Sales JSON').all().map(i => i.json);
const suppliers = $('Read Suppliers JSON').all().map(i => i.json);
const goal      = $('Set Goal').first().json.goal;

const stockout_risk = inventory
  .filter(r => Number(r.on_hand) <= Number(r.reorder_point))
  .map(r => ({ sku: r.sku, name: r.name,
               on_hand: Number(r.on_hand),
               reorder_point: Number(r.reorder_point) }));

const overstock_risk = inventory
  .filter(r => Number(r.on_hand) > Number(r.reorder_point) * 5)
  .map(r => ({ sku: r.sku, name: r.name,
               on_hand: Number(r.on_hand),
               reorder_point: Number(r.reorder_point) }));

const supplier_summary = suppliers.map(s => ({
  supplier_id: s.supplier_id,
  on_time_rate: Number(s.on_time_rate),
  defect_rate: Number(s.defect_rate),
}));

return [{
  json: {
    goal,
    context_summary: {
      sku_count: inventory.length,
      sales_rows: sales.length,
      stockout_risk,
      overstock_risk,
      supplier_summary,
    },
  },
}];

/**
 * Extract the Master Planner's JSON from the Anthropic response envelope.
 * Anthropic returns { content: [{ type: "text", text: "..." }], ... }.
 *
 * If your planner replies with markdown fences (```json ...```), the
 * JSON.parse below will fail. Forbid fences in your system prompt
 * (preferred) or strip them here.
 */
const raw = $json.content[0].text.trim();
let plan;
try {
  plan = JSON.parse(raw);
} catch (e) {
  throw new Error("Planner did not return valid JSON. Got:\n" + raw.slice(0, 500));
}

// Pull the goal+context through so downstream branches can reference them.
const ctx = $('Build Context Summary').first().json;

return [{ json: { ...plan, _goal: ctx.goal, _context: ctx.context_summary } }];

/**
 * Demand Forecasting Engine — classical statistical forecast.
 *
 * Pedagogical purpose
 * -------------------
 * This Code node implements the *classical* half of a hybrid planning
 * pipeline. It produces a deterministic, reproducible numeric forecast
 * for each SKU using:
 *   1. A 3-month moving average over recent demand
 *   2. A 12-month seasonal index that adjusts for cyclical patterns
 *
 * The downstream LLM node ("Forecast Context Adjuster") will take these
 * numbers and revise them using context the math cannot see — promotions,
 * news events, weather, viral product mentions. That handoff is the whole
 * point of the lesson: classical statistics for what is computable,
 * LLM reasoning for what is contextual.
 *
 * If your forecast looks suspicious (e.g. SKU-007 Wool Gloves projects
 * its low summer baseline forward), you have correctly built a *naive*
 * forecaster. The next node is supposed to catch what you missed.
 *
 * Reading: docs/planning-primer.md §"Classical vs LLM-based planning"
 */

// ---- Input contract -------------------------------------------------------
// This node's wired input is the routed plan object (from the Switch), not
// the sales rows -- same cross-node-reference pattern as Build Context
// Summary and Build Shipping Requests use elsewhere in this workflow.
// item.json = {month, sku, name, units_sold} (the parsed sales_history.csv).
const sales = $('Read Sales JSON').all().map(i => i.json);

// ---- Helpers (provided — do not change) -----------------------------------

function groupBySku(rows) {
  const out = {};
  for (const r of rows) {
    (out[r.sku] = out[r.sku] || []).push(r);
  }
  // Sort each SKU's series chronologically so "last 3" really means "most recent."
  for (const sku of Object.keys(out)) {
    out[sku].sort((a, b) => a.month.localeCompare(b.month));
  }
  return out;
}

function nextMonth(monthStr) {
  // "2025-12" -> "2026-01"
  const [y, m] = monthStr.split("-").map(Number);
  const d = new Date(Date.UTC(y, m, 1));
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, "0")}`;
}

// ---- The two algorithms YOU implement -------------------------------------

/**
 * Compute a simple 3-month moving average over the most recent units_sold values.
 *
 * @param {Array<{units_sold: number}>} series  Full sorted series for one SKU.
 * @returns {number}  Mean of the last 3 months. If fewer than 3 months of
 *                    data exist, take the mean of what's available.
 *                    Empty series -> 0.
 *
 * Why this matters: the moving average is the simplest possible "trend"
 * estimator. It's a STRIPS-style assumption: we assume the recent past
 * predicts the near future. This breaks for viral products and discontinued
 * items — which is exactly why the seasonal index and the LLM step exist.
 */
function movingAverage(series) {
  if (series.length === 0) return 0;
  const last3 = series.slice(-3);
  const sum = last3.reduce((acc, r) => acc + Number(r.units_sold), 0);
  return sum / last3.length;
}

/**
 * Seasonal index for a target forecast month.
 *
 * Definition for month M:
 *   index(M) = mean(units_sold across rows where month-of-year == M)
 *              / mean(units_sold across the entire series)
 *
 * Interpretation: 1.0 = "average month", 1.5 = "this month historically runs
 * 50% above average", 0.4 = "this month historically runs 60% below average."
 *
 * With only 12 months of history, the per-month mean degenerates to the
 * single observation we have for that month. That's a known weakness — we
 * accept it for this exercise. Production seasonality models use 2+ years.
 *
 * @param {Array<{month: string, units_sold: number}>} series
 * @param {string} targetMonth  e.g. "2026-01" — only the "01" portion matters.
 * @returns {number}            Multiplier. Default to 1.0 if you can't compute one.
 */
function seasonalIndex(series, targetMonth) {
  if (series.length === 0) return 1.0;

  const monthPart = targetMonth.split("-")[1];
  const monthRows = series.filter(r => r.month.split("-")[1] === monthPart);
  if (monthRows.length === 0) return 1.0;

  const mean = rows => rows.reduce((acc, r) => acc + Number(r.units_sold), 0) / rows.length;
  const monthMean = mean(monthRows);
  const overallMean = mean(series);

  if (overallMean === 0) return 1.0;
  return monthMean / overallMean;
}

// ---- Main loop (provided) -------------------------------------------------

const bySku = groupBySku(sales);
const results = [];

for (const sku of Object.keys(bySku)) {
  const series = bySku[sku];
  const last = series[series.length - 1].month;
  const target = nextMonth(last);

  // Classical forecast = trend (moving average) × seasonality
  const ma = movingAverage(series);
  const si = seasonalIndex(series, target);
  const forecast = ma * si;

  // Crude statistical confidence — coefficient of variation, inverted.
  // The downstream LLM is supposed to revise this when context demands it.
  // Watch how often statistical confidence and contextual confidence diverge.
  const variance = series.length > 1
    ? series.reduce((acc, r) => acc + Math.pow(r.units_sold - ma, 2), 0) / series.length
    : 0;
  const cv = ma > 0 ? Math.sqrt(variance) / ma : 1;
  const confidence = Math.max(0, Math.min(1, 1 - cv));

  results.push({
    sku,
    name: series[0].name,
    target_month: target,
    forecast_units: Math.round(forecast),
    moving_avg: Math.round(ma * 10) / 10,
    seasonal_index: Math.round(si * 100) / 100,
    statistical_confidence: Math.round(confidence * 100) / 100,
    method: "moving_avg_3 × seasonal_index",
    notes: [],
  });
}

// n8n Code-node return contract: array of {json: ...}
return results.map(r => ({ json: r }));

/**
 * Inventory Optimization Planner — Economic Order Quantity (EOQ).
 *
 * Pedagogical purpose
 * -------------------
 * EOQ (Wilson, 1934) is the canonical *classical* operations-research model:
 * a closed-form solution under strict assumptions —
 *   - constant demand
 *   - instantaneous replenishment
 *   - no stockouts allowed
 *   - fixed ordering cost, fixed holding cost
 *   - no quantity discounts
 *
 * Real e-commerce violates ALL of these for at least some SKUs. Viral
 * products (looking at you, SKU-007) blow past "constant demand." Discontinued
 * SKUs (SKU-013) make "no stockouts" expensive in the wrong direction.
 * Slow-movers make the formula numerically unstable.
 *
 * This node teaches the boundary problem: classical algorithms give crisp
 * answers exactly when their assumptions hold. Your two TODOs are
 *   (a) implement the formula
 *   (b) detect when its assumptions don't hold for a given SKU
 *
 * The downstream LLM exception node handles the SKUs you flag.
 *
 * Reading: docs/planning-primer.md §"STRIPS-style assumptions and where they break"
 */

// This node's wired input is the routed plan object (from the Switch), not
// the CSV rows -- pull inventory and sales via cross-node references instead
// (same pattern as Build Context Summary / Build Shipping Requests) and
// merge into one heterogeneous list. Partition them by which fields are present.
const all = [...$('Read Inventory JSON').all(), ...$('Read Sales JSON').all()].map(i => i.json);

// Default ordering cost (S in the EOQ formula). In production this would
// vary by supplier and channel; we hard-code a single value so the focus
// stays on the formula and its assumptions.
const ORDERING_COST_USD = 50;

// ---- Helpers (provided) ---------------------------------------------------

function partition(rows) {
  const inventory = rows.filter(r => "on_hand" in r);
  const sales = rows.filter(r => "units_sold" in r);
  return { inventory, sales };
}

function annualDemand(salesForSku) {
  // Sum units_sold across the rows we have. With 12 months of data this is
  // the trailing-12-months annual demand.
  return salesForSku.reduce((acc, r) => acc + Number(r.units_sold), 0);
}

// ---- TODO #1 — the EOQ formula --------------------------------------------

/**
 * Wilson's Economic Order Quantity:
 *
 *   Q* = sqrt( (2 * D * S) / H )
 *
 * @param {number} D  Annual demand        (units per year)
 * @param {number} S  Fixed cost per order (dollars per order)
 * @param {number} H  Holding cost         (dollars per unit per year)
 * @returns {number}  Optimal order quantity, rounded to nearest integer.
 *
 * Hint: Math.sqrt is your friend. Guard against D=0 and H=0 — return 0 in
 *       either case. (You can't optimally order anything for zero demand,
 *       and dividing by zero holding cost is meaningless.)
 */
function eoq(D, S, H) {
  if (D === 0 || H === 0) return 0;
  return Math.round(Math.sqrt((2 * D * S) / H));
}

// ---- TODO #2 — assumption-violation detection -----------------------------

/**
 * EOQ assumes:
 *   (a) demand is roughly constant
 *   (b) lead time is short enough to re-order before stocking out
 *   (c) the SKU isn't perishable (no holding-cost cliff)
 *   (d) demand volume is high enough that an "optimal batch" is meaningful
 *
 * Return an array of human-readable flag strings for any assumption that
 * FAILS for this SKU. An empty array means "EOQ is trustworthy here, ship
 * the formula's recommendation."
 *
 * Suggested checks (refine as you wish):
 *   - "viral_spike"   : mean(last 3 months) > 2.5 × mean(prior 9 months)
 *   - "declining"     : mean(last 3 months) < 0.5 × mean(first 3 months)
 *   - "low_velocity"  : annualDemand < 60   (less than ~5/month average)
 *   - "long_lead_time": inv.lead_time_days > 28 AND demand is volatile
 *
 * Note on perishability: none of our demo SKUs are perishable, so you do
 * NOT need a perishability check. Document the omission in your analysis
 * write-up — a real implementation would need it.
 *
 * @param {object} inv         Inventory row for the SKU
 * @param {Array}  salesSeries Chronologically sorted sales rows for the SKU
 * @returns {Array<string>}    Flag names, e.g. ["viral_spike", "low_velocity"]
 *
 * Hint: implement each check as its own small block. A flagged SKU may
 *       trigger multiple flags — that's expected and useful downstream.
 */
function detectViolations(inv, salesSeries) {
  const flags = [];
  if (salesSeries.length === 0) return flags;

  const mean = rows => rows.length
    ? rows.reduce((acc, r) => acc + Number(r.units_sold), 0) / rows.length
    : 0;

  // (a) demand is roughly constant -- recent months vs. the rest of the year.
  const last3 = salesSeries.slice(-3);
  const prior9 = salesSeries.slice(0, -3);
  if (prior9.length > 0 && mean(last3) > 2.5 * mean(prior9)) {
    flags.push("viral_spike");
  }

  // Mirror check: demand trailing off relative to where it started.
  const first3 = salesSeries.slice(0, 3);
  if (mean(first3) > 0 && mean(last3) < 0.5 * mean(first3)) {
    flags.push("declining");
  }

  // (d) volume high enough for an "optimal batch" to be meaningful.
  const D = annualDemand(salesSeries);
  if (D < 60) {
    flags.push("low_velocity");
  }

  // (b) lead time short enough to re-order before stocking out -- only a
  // real problem when demand is also volatile (coefficient of variation).
  const overallMean = mean(salesSeries);
  const variance = salesSeries.reduce(
    (acc, r) => acc + Math.pow(Number(r.units_sold) - overallMean, 2), 0
  ) / salesSeries.length;
  const cv = overallMean > 0 ? Math.sqrt(variance) / overallMean : 0;
  const isVolatile = cv > 0.4;
  if (Number(inv.lead_time_days) > 28 && isVolatile) {
    flags.push("long_lead_time");
  }

  return flags;
}

// ---- Main loop (provided) -------------------------------------------------

const { inventory, sales } = partition(all);
const salesBySku = sales.reduce((acc, r) => {
  (acc[r.sku] = acc[r.sku] || []).push(r);
  return acc;
}, {});
for (const sku of Object.keys(salesBySku)) {
  salesBySku[sku].sort((a, b) => a.month.localeCompare(b.month));
}

const results = [];
for (const inv of inventory) {
  const series = salesBySku[inv.sku] || [];
  const D = annualDemand(series);
  const H = Number(inv.holding_cost_per_unit_year);
  const Q = eoq(D, ORDERING_COST_USD, H);
  const flags = detectViolations(inv, series);

  results.push({
    sku: inv.sku,
    name: inv.name,
    on_hand: Number(inv.on_hand),
    reorder_point: Number(inv.reorder_point),
    annual_demand: D,
    eoq_units: Q,
    holding_cost_per_unit_year: H,
    ordering_cost_usd: ORDERING_COST_USD,
    assumption_flags: flags,
    needs_llm_review: flags.length > 0,
  });
}

return results.map(r => ({ json: r }));

/**
 * Classical Logistics Planner — greedy fallback.
 *
 * Pedagogical purpose
 * -------------------
 * This is the "planning without an LLM" branch of the Logistics Coordinator.
 * The LLM logistics node handles soft-constraint cases (special instructions,
 * supplier relationships, urgency framing, multi-leg trade-offs). When the
 * upstream IF node decides a situation is purely numerical — fixed weight,
 * fixed deadline, available carriers — it routes here for a deterministic,
 * auditable choice.
 *
 * Greedy is the simplest classical search: at each decision point, take the
 * locally best option. It's not always globally optimal, but it's fast,
 * explainable, and a perfect baseline to compare LLM plans against.
 *
 * Reading: docs/planning-primer.md §"Classical search and the cost of optimality"
 */

// This node's wired input is whichever Logistics Coordinator (LLM) outputs
// set use_classical_fallback: true -- i.e. request_id + chosen_option_id +
// trade_off_summary, NOT the full request (weight_kg, deadline_days, etc.).
// Use $input to know WHICH requests need fallback, then look up each one's
// full data by request_id via cross-node reference (same pattern used
// elsewhere in this workflow). The options catalogue is a plain cross-ref.
//
// A request: { type: "request", request_id, weight_kg, origin_region,
//              dest_region, deadline_days, perishable }
// An option: { option_id, carrier, mode, origin_region, destination_region,
//              transit_days, cost_per_kg, max_weight_kg, supports_perishable }

const needsFallback = $input.all().map(i => i.json);
const allRequests = $('Build Shipping Requests').all().map(i => i.json);
const options = $('Read Shipping JSON').all().map(i => i.json);

const requests = needsFallback
  .map(inc => allRequests.find(r => r.request_id === inc.request_id))
  .filter(Boolean);

// ---- TODO — greedy carrier assignment -------------------------------------

/**
 * Pick the cheapest shipping option satisfying ALL hard constraints
 * for one request:
 *   - origin_region matches request.origin_region
 *   - destination_region matches request.dest_region
 *   - transit_days <= request.deadline_days
 *   - max_weight_kg >= request.weight_kg
 *   - if request.perishable === true, supports_perishable must also be true
 *
 * Total cost = request.weight_kg × option.cost_per_kg  (we ignore time cost)
 *
 * @param {object} req
 * @param {Array}  options
 * @returns {object|null}  Chosen option augmented with `total_cost_usd`,
 *                         or null if nothing satisfies the constraints.
 *
 * Hint: this is two steps — filter, then min-by-cost.
 *   1. Array.prototype.filter against the 5 hard constraints.
 *   2. If the filtered list is empty, return null (infeasible).
 *   3. Map each survivor to {...option, total_cost_usd: req.weight_kg * option.cost_per_kg}.
 *   4. Reduce to the one with the minimum total_cost_usd.
 *
 * Why greedy and not exhaustive? With ~10 options per request the search
 * space is trivial. We use greedy to keep the comparison clean against
 * the LLM branch, not because we couldn't afford the optimal search.
 */
function pickCheapestFeasible(req, options) {
  const feasible = options.filter(o =>
    o.origin_region === req.origin_region &&
    o.destination_region === req.dest_region &&
    Number(o.transit_days) <= Number(req.deadline_days) &&
    Number(o.max_weight_kg) >= Number(req.weight_kg) &&
    (!req.perishable || o.supports_perishable === true || o.supports_perishable === "true")
  );

  if (feasible.length === 0) return null;

  const priced = feasible.map(o => ({
    ...o,
    total_cost_usd: Number(req.weight_kg) * Number(o.cost_per_kg),
  }));

  return priced.reduce((cheapest, o) =>
    o.total_cost_usd < cheapest.total_cost_usd ? o : cheapest
  );
}

// ---- Main loop (provided) -------------------------------------------------

const assignments = [];
for (const req of requests) {
  const choice = pickCheapestFeasible(req, options);
  assignments.push({
    request_id: req.request_id,
    weight_kg: req.weight_kg,
    deadline_days: req.deadline_days,
    chosen: choice,
    feasible: choice !== null,
    method: "classical_greedy",
  });
}

return assignments.map(a => ({ json: a }));

/**
 * Aggregate the active subgoal's output into a final business-friendly summary.
 * Only one branch fires per execution (the Switch routes on next_subgoal).
 *
 * next_recommended_subgoal is read off the Master Planner's own subgoals
 * ordering (not a hardcoded sequence) -- this is the seed of an iterative
 * HTN loop: feed it back into the planner on the next run to advance the
 * plan one step at a time.
 */
const items = $input.all().map(i => i.json);
const plan = $('Parse Plan').first().json;
const executed_subgoal = plan.next_subgoal;

function extractLLMJson(item) {
  // Raw Anthropic envelope shape: { content: [{ type: "text", text: "..." }], ... }
  const text = item && Array.isArray(item.content) && item.content[0] && item.content[0].text;
  if (typeof text !== "string") return item;
  try {
    return JSON.parse(text.trim());
  } catch (e) {
    return { parse_error: text.slice(0, 300) };
  }
}

const parsed = items.map(extractLLMJson);

// Supplier Monitor returns one array-shaped item (all suppliers at once);
// every other branch returns one object per item already. Flatten either way.
const key_findings = [];
for (const p of parsed) {
  if (Array.isArray(p)) key_findings.push(...p);
  else key_findings.push(p);
}

const subgoals = plan.subgoals || [];
const currentIdx = subgoals.findIndex(sg => sg.type === executed_subgoal);
const next_recommended_subgoal =
  currentIdx >= 0 && currentIdx < subgoals.length - 1
    ? subgoals[currentIdx + 1].type
    : null;

return [{
  json: {
    plan_id: plan.plan_id,
    executed_subgoal,
    key_findings,
    next_recommended_subgoal,
  },
}];

/**
 * Extract each Logistics Coordinator response's JSON from the Anthropic
 * response envelope -- same JSON.parse pattern Parse Plan uses for the
 * Master Planner, but looped: unlike the Master Planner (which runs once),
 * this node runs once PER SHIPPING REQUEST, so $input holds one item per
 * request and must be iterated explicitly (a bare $json here would only
 * see the first item).
 */
const items = $input.all();
const results = [];
for (const item of items) {
  const raw = item.json.content[0].text.trim();
  let decision;
  try {
    decision = JSON.parse(raw);
  } catch (e) {
    throw new Error("Logistics Coordinator did not return valid JSON. Got:\n" + raw.slice(0, 500));
  }
  results.push({ json: decision });
}
return results;
